        composeTestRule.onNodeWithTag("nav_item_characters").performClick()
        composeTestRule.onNodeWithContentDescription(
            composeTestRule.activity.getString(R.string.content_desc_add_character)
        ).performClick()
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.label_name)
        ).performTextInput("Kira")
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.label_race)
        ).performTextInput("Elf")
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.button_confirm)
        ).performClick()

        // Create a weapon and assign it to the character
        composeTestRule.onNodeWithTag("nav_item_weapons").performClick()
        composeTestRule.onNodeWithContentDescription(
            composeTestRule.activity.getString(R.string.content_desc_add_weapon)
        ).performClick()
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.label_name)
        ).performTextInput("Elven Bow")
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.label_weapon_type)
        ).performTextInput("Ranged")
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.label_damage_dice)
        ).performTextInput("1d8")
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.label_damage_type)
        ).performTextInput("Piercing")
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.button_confirm)
        ).performClick()
        composeTestRule.onNodeWithContentDescription(
            composeTestRule.activity.getString(R.string.content_desc_assign)
        ).performClick()
        composeTestRule.onNodeWithText("Kira").performClick()

        // Go to characters screen and tap the weapon chip
        composeTestRule.onNodeWithTag("nav_item_characters").performClick()
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.format_weapon_chip_label, "Elven Bow", "Ranged")
        ).performClick()

        // Verify we are on the weapons screen with the edit dialog open
        composeTestRule.onNodeWithTag("screen_title_weapons").assertIsDisplayed()
        composeTestRule.onNodeWithText(
            composeTestRule.activity.getString(R.string.title_edit_weapon)
        ).assertIsDisplayed()
        composeTestRule.onNodeWithText("Elven Bow").assertIsDisplayed()
    }
}

package com.hdarby.dicemaster.ui.screens

import androidx.activity.ComponentActivity
import androidx.compose.ui.test.assertIsDisplayed
import androidx.compose.ui.test.junit4.createAndroidComposeRule
import androidx.compose.ui.test.onNodeWithContentDescription
import androidx.compose.ui.test.onNodeWithTag
import androidx.compose.ui.test.onNodeWithText
import androidx.compose.ui.test.performClick
import com.hdarby.dicemaster.R
import com.hdarby.dicemaster.domain.model.Character
import com.hdarby.dicemaster.domain.model.CharacterWithWeapons
import com.hdarby.dicemaster.domain.model.Stats
import com.hdarby.dicemaster.domain.model.Weapon
import com.hdarby.dicemaster.ui.theme.DiceMasterTheme
import org.junit.Assert.assertTrue
import org.junit.Rule
import org.junit.Test

class CharacterScreenTest {

    @get:Rule
    val composeTestRule = createAndroidComposeRule<ComponentActivity>()

    private val testCharacter = Character(
        id = 1,
        name = "Grog",
        race = "Goliath",
        stats = Stats(
            strength = 20, strengthModifier = 5,
            dexterity = 12, dexterityModifier = 1,
            constitution = 18, constitutionModifier = 4,
            intelligence = 6, intelligenceModifier = -2,
            wisdom = 10, wisdomModifier = 0,
            charisma = 8, charismaModifier = -1
        )
    )

    private val testWeapon = Weapon(
        id = 1,
        name = "Greataxe",
        type = "Heavy",
        damageDice = "1d12",
        damageType = "Slashing",
        modifier = 2
    )

    @Test
    fun characterCard_displaysCharacterInfo() {
        composeTestRule.setContent {
            DiceMasterTheme {
                CharacterCard(
                    characterWithWeapons = CharacterWithWeapons(testCharacter, emptyList()),
                    onEdit = {},
                    onDelete = {}
                )
            }
        }

        composeTestRule.onNodeWithText("Grog").assertIsDisplayed()
        composeTestRule.onNodeWithText("Goliath").assertIsDisplayed()
        composeTestRule.onNodeWithText("20").assertIsDisplayed() // STR
        composeTestRule.onNodeWithText("12").assertIsDisplayed() // DEX
    }

    @Test
    fun characterCard_displaysWeapons() {
        composeTestRule.setContent {
            DiceMasterTheme {
                CharacterCard(
                    characterWithWeapons = CharacterWithWeapons(testCharacter, listOf(testWeapon)),
                    onEdit = {},
                    onDelete = {}
                )
            }
        }

        composeTestRule.onNodeWithText("Greataxe (Heavy)").assertIsDisplayed()
    }

    @Test
    fun characterCard_callsOnEditWhenEditClicked() {
        var editCalled = false
        var editedCharacter: Character? = null

        composeTestRule.setContent {
            DiceMasterTheme {
                CharacterCard(
                    characterWithWeapons = CharacterWithWeapons(testCharacter, emptyList()),
                    onEdit = {
                        editCalled = true
                        editedCharacter = it
                    },
                    onDelete = {}
                )
            }
        }

        composeTestRule.onNodeWithContentDescription(
            composeTestRule.activity.getString(R.string.content_desc_edit)
        ).performClick()

        assertTrue(editCalled)
        assertTrue(editedCharacter?.id == testCharacter.id)
    }

    @Test
    fun characterCard_callsOnDeleteWhenDeleteClicked() {
        var deleteCalled = false
        var deletedCharacter: Character? = null

        composeTestRule.setContent {
            DiceMasterTheme {
                CharacterCard(
                    characterWithWeapons = CharacterWithWeapons(testCharacter, emptyList()),
                    onEdit = {},
                    onDelete = {
                        deleteCalled = true
                        deletedCharacter = it
                    }
                )
            }
        }

        composeTestRule.onNodeWithContentDescription(
            composeTestRule.activity.getString(R.string.content_desc_delete)
        ).performClick()

        assertTrue(deleteCalled)
