        composeTestRule.setContent {
            DiceMasterTheme {
                CharacterCard(
                    characterWithWeapons = CharacterWithWeapons(testCharacter, listOf(testWeapon)),
                    onEdit = {},
                    onDelete = {},
                    onWeaponClick = {
